      data_hora_pre_reserva: nullableStr(resumoLeadJson.data_hora_pre_reserva || row.data_hora_pre_reserva),
      responsavel_humano: nullableStr(resumoLeadJson.responsavel_humano || row.responsavel_humano),
      observacoes: nullableStr(resumoLeadJson.observacoes || inferObservacoesResumoLead(row))
    },

