    deve_repassar_humano: deveRepassarHumano,
    motivo_repasse: nullableStr(row.motivo_repasse),
    deve_enviar_guia: !guiaEnviado && str(row.status_lead) === 'APTO_PARA_AVALIACAO',
    deve_solicitar_pagamento: (
      str(row.status_lead) === 'AGUARDANDO_PAGAMENTO' ||
