    ),
    deve_consultar_agenda: str(row.status_lead) === 'AGUARDANDO_ESCOLHA_HORARIO',
    deve_criar_pre_reserva: !preReservaCriada && !!row.data_hora_avaliacao && comprovanteRecebido,
    deve_encerrar_conversa: encerrado || str(row.status_lead).startsWith('ENCERRADO'),
    mensagem_ultima_lead: nullableStr(row.mensagem_ultima_lead),
    mensagem_ultima_bruna: nullableStr(row.mensagem_ultima_bruna),

    resumo_interno_repasse: {
      repassar_para: nullableStr(resumoRepasseJson.repassar_para || row.responsavel_humano),
      motivo: nullableStr(resumoRepasseJson.motivo || row.motivo_repasse),
      tutor_nome: nullableStr(resumoRepasseJson.tutor_nome || row.nome_tutor),
      tutor_telefone: nullableStr(resumoRepasseJson.tutor_telefone || telefone),
      cao_nome: nullableStr(resumoRepasseJson.cao_nome || row.nome_cao),
      cao_idade_anos: nullableStr(resumoRepasseJson.cao_idade_anos || row.idade_cao_anos),
      cao_raca: nullableStr(resumoRepasseJson.cao_raca || row.cao_raca),
      cao_porte: nullableStr(resumoRepasseJson.cao_porte || row.cao_porte),
      cao_sexo: nullableStr(resumoRepasseJson.cao_sexo || row.cao_sexo),
      cao_castrado: nullableStr(resumoRepasseJson.cao_castrado || row.cao_castrado),
      cao_vacinas_ok: nullableStr(resumoRepasseJson.cao_vacinas_ok || row.cao_vacinas_ok),
      cao_antipulgas_ok: nullableStr(resumoRepasseJson.cao_antipulgas_ok || row.cao_antipulgas_ok),
      cao_sociavel: nullableStr(resumoRepasseJson.cao_sociavel || row.cao_sociavel),
      cao_reativo: nullableStr(resumoRepasseJson.cao_reativo || row.cao_reativo),
      unidade_preferida: nullableStr(resumoRepasseJson.unidade_preferida || row.unidade_preferida),
      servico_interesse: nullableStr(resumoRepasseJson.servico_interesse || row.servico_interesse),
      data_hora_avaliacao: nullableStr(resumoRepasseJson.data_hora_avaliacao || row.data_hora_avaliacao),
      comprovante_recebido: comprovanteRecebido,
      tipo_comprovante: nullableStr(resumoRepasseJson.tipo_comprovante || row.tipo_comprovante),
      observacoes: nullableStr(resumoRepasseJson.observacoes || inferObservacoesRepasse(row))
    }
  };

  return {
    json: {
      inputs
    }
  };
});

function removeEmpty(value) {
  if (Array.isArray(value)) {
    return value
      .map(removeEmpty)
      .filter(v => v !== null && v !== undefined && v !== '');
  }

  if (value && typeof value === 'object') {
    const out = {};

    for (const [key, val] of Object.entries(value)) {
      const cleaned = removeEmpty(val);

      if (cleaned === null || cleaned === undefined || cleaned === '') continue;
      if (Array.isArray(cleaned) && cleaned.length === 0) continue;
      if (
        typeof cleaned === 'object' &&
        !Array.isArray(cleaned) &&
        Object.keys(cleaned).length === 0
      ) continue;

      out[key] = cleaned;
    }

    return out;
  }

  return value;
}

function clean(value, preserveNewLines = true) {
  let text = String(value ?? '')
    .replace(/\[object Object\]/gi, '')
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, ' ')
    .replace(/\uFFFD/g, ' ')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n');

  if (preserveNewLines) {
    return text
      .split('\n')
      .map(line => line.replace(/[ \t]+/g, ' ').trim())
      .filter(Boolean)
      .join('\n')
      .trim();
  }

  return text.replace(/\s+/g, ' ').trim();
}

function pick(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && String(value).trim() !== '') {
      return value;
    }
  }

  return '';
}

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function getChatwootMessages(histItem) {
  const candidates = [
    histItem?.chatwoot_messages,
    histItem?.chatwoot?.chatwoot_messages,
    histItem?.messages_for_crm,
    histItem?.messages,
    histItem?.payload,
    histItem?.data?.payload,
    histItem?.data?.messages
  ];

  for (const candidate of candidates) {
    if (Array.isArray(candidate)) return candidate;
  }

  return [];
}

function getRole(msg) {
  if (msg?.role) return String(msg.role);

  if (Number(msg?.message_type) === 0) return 'lead';
  if (Number(msg?.message_type) === 1) return msg?.private ? 'sistema' : 'bruna';

  return 'sistema';
}

function relevantText(text) {
  const t = clean(text, true);

  if (!t) return false;
  if (/^(ok|obrigado|obrigada|obg|valeu|👍|👌|🙏|❤️|❤|kkk|rs|rsrs)$/i.test(t)) return false;

  return true;
}

function getLastMessageByRole(messages, role) {
  const filtered = messages
    .filter(msg => getRole(msg) === role)
    .filter(msg => relevantText(msg?.content));

  if (!filtered.length) return '';

  return clean(filtered[filtered.length - 1].content, true);
}

function getFirstId(messages) {
  const ids = messages
    .map(msg => Number(msg?.id))
    .filter(Number.isFinite);

  return ids.length ? Math.min(...ids) : null;
}

function getLastId(messages) {
  const ids = messages
    .map(msg => Number(msg?.id))
    .filter(Number.isFinite);

  return ids.length ? Math.max(...ids) : null;
}

const baseItem = $('Histórico Atualizado').first().json || {};
const histItem = $json || {};

const histMessage = histItem.message && typeof histItem.message === 'object'
  ? histItem.message
  : {};

const histInputs = histItem.inputs && typeof histItem.inputs === 'object'
  ? histItem.inputs
  : {};

const histChatwoot = histItem.chatwoot && typeof histItem.chatwoot === 'object'
  ? histItem.chatwoot
  : {};

const baseMessage = baseItem.message && typeof baseItem.message === 'object'
  ? baseItem.message
  : {};

const baseInputs = baseItem.inputs && typeof baseItem.inputs === 'object'
  ? baseItem.inputs
  : {};

const baseChatwoot = baseItem.chatwoot && typeof baseItem.chatwoot === 'object'
  ? baseItem.chatwoot
  : {};

const chatwootMessages = getChatwootMessages(histItem);

const historyForCrm = clean(
  pick(
    histMessage.history_for_crm,
    histItem.history_for_crm,
    baseMessage.history_for_crm,
    baseItem.history_for_crm,
    ''
  ),
  true
);

const firstMessageId = pick(
  histMessage.first_message_id,
  histItem.first_message_id,
  getFirstId(chatwootMessages),
  baseMessage.first_message_id,
  null
);

const lastMessageId = pick(
  histMessage.last_message_id,
  histItem.last_message_id,
  getLastId(chatwootMessages),
  baseMessage.last_message_id,
  baseChatwoot.message_id,
  null
);

const lastLeadMessage = clean(
  pick(
    histItem.last_lead_message,
    histInputs?.diagnostico_crm?.ultima_mensagem_relevante_lead,
    histInputs?.mensagem_ultima_lead,
    getLastMessageByRole(chatwootMessages, 'lead'),
    baseItem.last_lead_message,
    baseInputs.mensagem_ultima_lead,
    baseMessage.content,
    ''
  ),
  true
);

const lastBrunaMessage = clean(
  pick(
    histItem.last_bruna_message,
    histInputs?.diagnostico_crm?.ultima_mensagem_relevante_bruna,
    histInputs?.mensagem_ultima_bruna,
    getLastMessageByRole(chatwootMessages, 'bruna'),
    baseItem.last_bruna_message,
    baseInputs.mensagem_ultima_bruna,
    ''
  ),
  true
);

const lastHumanMessage = clean(
  pick(
    histItem.last_human_message,
    getLastMessageByRole(chatwootMessages, 'humano'),
    baseItem.last_human_message,
    ''
  ),
  true
);

// IMPORTANTE:
// message.content deve continuar sendo a mensagem atual/consolidada do lead.
// Não use histItem.message como content, porque histItem.message é metadado do histórico.
const currentMessageContent = clean(
  pick(
    baseMessage.content,
    baseMessage.content_last_message,
    baseItem.content,
    lastLeadMessage,
    ''
  ),
  true
);

const output = {
  ...baseItem,

  message: {
    ...baseMessage,

    content: currentMessageContent,
    content_raw: currentMessageContent,
    content_last_message: currentMessageContent,

    historico: clean(
      pick(
        histMessage.historico,
        histItem.source,
        baseMessage.historico,
        'historico'
      ),
      false
    ),

    history_for_crm: historyForCrm,

    first_message_id: firstMessageId,
    last_message_id: lastMessageId
  },

  inputs: {
    ...baseInputs,
    ...histInputs,

    history_for_crm: historyForCrm,
    mensagem_ultima_lead: lastLeadMessage || baseInputs.mensagem_ultima_lead || '',
    mensagem_ultima_bruna: lastBrunaMessage || baseInputs.mensagem_ultima_bruna || '',
    last_human_message: lastHumanMessage || baseInputs.last_human_message || '',

    bloco_historico_chatwoot: {
      ...(baseInputs.bloco_historico_chatwoot || {}),
      carregado: chatwootMessages.length > 0,
      count: chatwootMessages.length,
      first_message_id: firstMessageId,
      last_message_id: lastMessageId
    }
  },

  chatwoot: {
    ...baseChatwoot,

    // Não deixe o histChatwoot apagar account_id, conversation_id, contact_id, labels etc.
    ...Object.fromEntries(
      Object.entries(histChatwoot).filter(([key]) => key !== 'chatwoot_messages')
    ),

    account_id: pick(histChatwoot.account_id, baseChatwoot.account_id, baseItem.account_id),
    contact_id: pick(histChatwoot.contact_id, baseChatwoot.contact_id, baseItem.contact_id),
    conversation_id: pick(histChatwoot.conversation_id, baseChatwoot.conversation_id, baseItem.conversation_id),
    inbox_id: pick(histChatwoot.inbox_id, baseChatwoot.inbox_id, baseItem.inbox_id),
    message_id: pick(lastMessageId, baseChatwoot.message_id, baseItem.message_id),

    first_message_id: firstMessageId,
    last_message_id: lastMessageId,

    chatwoot_messages: chatwootMessages
  },

  // Top-level obrigatório para o NORMALIZA BLOCO MENSAGENS LEAD encontrar.
  chatwoot_messages: chatwootMessages,

  // Top-level útil para Analista CRM e guards.
  history_for_crm: historyForCrm,
  last_lead_message: lastLeadMessage,
  last_bruna_message: lastBrunaMessage,
  last_human_message: lastHumanMessage,

  first_message_id: firstMessageId,
  last_message_id: lastMessageId,

  historico_merge_debug: {
    ok: true,
    chatwoot_messages_count: chatwootMessages.length,
    first_message_id: firstMessageId,
    last_message_id: lastMessageId,
    manteve_chatwoot_base: true,
    expôs_chatwoot_messages_top_level: true,
    corrigiu_message_content_para_nao_usar_objeto: true
  }
};

return [{ json: output }];

const item = $json || {};

function pick(...values) {
  for (const v of values) {
    if (v !== undefined && v !== null && String(v).trim() !== '') return v;
  }
  return '';
}

function norm(v) {
  return String(v ?? '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .trim()
    .toLowerCase();
}

function bool(v) {
