function pick(...values) {
  for (const v of values) {
    if (v !== undefined && v !== null && String(v).trim() !== '') return v;
  }
  return '';
}

function safeString(v) {
  if (v === undefined || v === null) return '';
  if (typeof v === 'object') {
    try {
      return JSON.stringify(v);
    } catch (e) {
      return '';
    }
  }
  return String(v);
}

function norm(v) {
  return safeString(v)
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .trim()
    .toLowerCase();
}

function isTrueLike(v) {
  const n = norm(v);
  return v === true || ['true', '1', 'sim', 'yes'].includes(n);
}

function isFalseLike(v) {
  const n = norm(v);

  if (v === false) return true;

  if (['false', '0', 'nao', 'não', 'no'].includes(n)) return true;

  return (
    /\bnao\b/.test(n) ||
    /\bnao e\b/.test(n) ||
    /\bnao eh\b/.test(n) ||
    /\bnao esta\b/.test(n) ||
    /\bnao ta\b/.test(n) ||
    /\bnao castrad[oa]\b/.test(n)
  );
}

function parseAgeYears(ageValue, ageText) {
  if (ageValue !== undefined && ageValue !== null && String(ageValue).trim() !== '') {
    const n = Number(String(ageValue).replace(',', '.'));
    if (!Number.isNaN(n)) return n;
  }

  const txt = norm(ageText);
  if (!txt) return null;

  const yearMatch = txt.match(/(\d+(?:[.,]\d+)?)\s*ano/);
  if (yearMatch) {
    const n = Number(yearMatch[1].replace(',', '.'));
    return Number.isNaN(n) ? null : n;
  }

  const monthMatch = txt.match(/(\d+(?:[.,]\d+)?)\s*mes/);
  if (monthMatch) {
    const n = Number(monthMatch[1].replace(',', '.'));
    return Number.isNaN(n) ? null : n / 12;
  }

  return null;
}

