function previousBrunaTextFrom(inputs) {
  return norm(pick(
    inputs.mensagem_ultima_bruna,
    inputs.last_ai_message,
    inputs.bruna_response
  ));
}

function leadRefusedFutureCastration(latestLeadText, previousBrunaText, allText) {
  const previousAsked =
    /pensa em castra|pretende castra|vai castra|castra-lo em breve|castra lo em breve/.test(previousBrunaText) ||
    /pensa em castra|pretende castra|vai castra|castra-lo em breve|castra lo em breve/.test(allText);

  const explicitRefusal =
    /nao pretendo castra|nao vou castra|nao penso em castra|sem previsao|nao tenho previsao|nao quero castra/.test(allText);

  const shortNoAfterQuestion =
    previousAsked &&
    /^(nao|não|n|negativo|nao tenho interesse|nao pretendo)(\b|\.|!|\?|$)/.test(latestLeadText);

  return explicitRefusal || shortNoAfterQuestion;
}

function leadWillCastrate(latestLeadText, previousBrunaText, allText) {
  const previousAsked =
    /pensa em castra|pretende castra|vai castra|castra-lo em breve|castra lo em breve/.test(previousBrunaText) ||
    /pensa em castra|pretende castra|vai castra|castra-lo em breve|castra lo em breve/.test(allText);

  const explicitYes =
    /vou castra|pretendo castra|penso em castra|quero castra|em breve|assim que/.test(allText);

  const shortYesAfterQuestion =
    previousAsked &&
    /^(sim|s|positivo|pretendo|vou|penso)(\b|\.|!|\?|$)/.test(latestLeadText);

  return explicitYes || shortYesAfterQuestion;
}

function fillResumoInternoRepasse(base, resumo, tutorNome, tutorTelefone, caoNome, idadeAnos, inputs) {
  return {
    ...base,
    repassar_para: String(pick(base.repassar_para, '') || ''),
    motivo: String(pick(base.motivo, '') || ''),
    tutor_nome: String(pick(base.tutor_nome, tutorNome, '') || ''),
    tutor_telefone: String(pick(base.tutor_telefone, tutorTelefone, '') || ''),
    cao_nome: String(pick(base.cao_nome, caoNome, '') || ''),
    cao_idade_anos: pick(base.cao_idade_anos, resumo.cao_idade_anos, idadeAnos, ''),
    cao_raca: String(pick(base.cao_raca, resumo.cao_raca, inputs.cao_raca, '') || ''),
    cao_porte: String(pick(base.cao_porte, resumo.cao_porte, inputs.cao_porte, '') || ''),
    cao_sexo: String(pick(base.cao_sexo, resumo.cao_sexo, inputs.cao_sexo, '') || ''),
    cao_castrado: String(pick(base.cao_castrado, resumo.cao_castrado, inputs.cao_castrado, '') || ''),
    cao_vacinas_ok: String(pick(base.cao_vacinas_ok, resumo.cao_vacinas_ok, inputs.cao_vacinas_ok, '') || ''),
    cao_antipulgas_ok: String(pick(base.cao_antipulgas_ok, resumo.cao_antipulgas_ok, inputs.cao_antipulgas_ok, '') || ''),
    cao_sociavel: String(pick(base.cao_sociavel, resumo.cao_sociavel, inputs.cao_sociavel, '') || ''),
    cao_reativo: String(pick(base.cao_reativo, resumo.cao_reativo, inputs.cao_reativo, '') || ''),
    unidade_preferida: String(pick(base.unidade_preferida, resumo.unidade_preferida, inputs.unidade_preferida, '') || ''),
    servico_interesse: String(pick(base.servico_interesse, resumo.servico_interesse, inputs.servico_interesse, '') || ''),
    data_hora_avaliacao: pick(base.data_hora_avaliacao, null),
    comprovante_recebido: isTrueLike(pick(base.comprovante_recebido, resumo.comprovante_recebido, false)),
    tipo_comprovante: String(pick(base.tipo_comprovante, resumo.tipo_comprovante, '') || ''),
    observacoes: String(pick(base.observacoes, '') || '')
  };
}

const montaBrunaItems = $items('Monta Bruna', 0, 0) || [];

return items.map((item, index) => {
  const current = item.json || {};
  const monta = montaBrunaItems[index]?.json || {};

  const brunaOutput =
    current.output && typeof current.output === 'object'
      ? current.output
      : current;

  const originalInputs =
    monta.inputs && typeof monta.inputs === 'object'
      ? monta.inputs
      : (current.inputs && typeof current.inputs === 'object' ? current.inputs : {});

  const mensagensResposta = Array.isArray(brunaOutput.mensagens_resposta)
    ? brunaOutput.mensagens_resposta
    : [];

  const j = {
    message: {
      ...(monta.message || current.message || {}),
      clean_answer: mensagensResposta.length > 0
        ? mensagensResposta.join('\n\n')
        : pick(
            monta.message?.clean_answer,
            current.message?.clean_answer,
            monta.message?.content,
            current.message?.content
          )
    },
    lead: {
      ...(monta.lead || current.lead || {})
    },
    chatwoot: {
      ...(monta.chatwoot || current.chatwoot || {})
    },
    inputs: {
      ...originalInputs,
      ...brunaOutput
    }
  };

  const inputs = j.inputs;

  inputs.resumo_lead = {
    ...defaultResumoLead(),
    ...(originalInputs.resumo_lead || {}),
    ...(brunaOutput.resumo_lead || {})
  };

  inputs.resumo_interno_repasse = {
    ...defaultResumoInternoRepasse(),
    ...(originalInputs.resumo_interno_repasse || {}),
    ...(brunaOutput.resumo_interno_repasse || {})
  };

  if (!Array.isArray(inputs.mensagens_resposta) || inputs.mensagens_resposta.length === 0) {
    inputs.mensagens_resposta = mensagensResposta.length > 0
      ? mensagensResposta
      : (pick(j.message.clean_answer) ? [j.message.clean_answer] : []);
  }

  if (!inputs.regras_raca || typeof inputs.regras_raca !== 'object') {
    inputs.regras_raca = originalInputs.regras_raca || {};
  }

  if (!inputs.calendario || typeof inputs.calendario !== 'object') {
    inputs.calendario = originalInputs.calendario || {};
  }

  inputs.status_lead = inputs.status_lead ?? '';
  inputs.ultima_intencao = inputs.ultima_intencao ?? '';
  inputs.evento_sistema = inputs.evento_sistema ?? '';
  inputs.proxima_acao = inputs.proxima_acao ?? '';

  inputs.deve_repassar_humano = Boolean(inputs.deve_repassar_humano);
  inputs.motivo_repasse = inputs.motivo_repasse ?? '';
  inputs.deve_enviar_guia = Boolean(inputs.deve_enviar_guia);
  inputs.deve_solicitar_pagamento = Boolean(inputs.deve_solicitar_pagamento);
  inputs.deve_consultar_agenda = Boolean(inputs.deve_consultar_agenda);
  inputs.deve_criar_pre_reserva = Boolean(inputs.deve_criar_pre_reserva);
  inputs.deve_encerrar_conversa = Boolean(inputs.deve_encerrar_conversa);

  const resumo = inputs.resumo_lead;
  const resumoInternoRepasse = inputs.resumo_interno_repasse;
  const regrasRaca = inputs.regras_raca || {};
  const message = j.message || {};
  const lead = j.lead || {};

  const tutorNome = pick(
    resumo.tutor_nome,
    inputs.nome_tutor,
    inputs.lead_name,
    lead.sender_name
  );

  const tutorTelefone = pick(
    resumo.tutor_telefone,
    inputs.phone,
    inputs.lead_phone,
    lead.phone
  );

  const caoNome = pick(
    resumo.cao_nome,
    inputs.nome_cao
  );

  const idadeAnos = parseAgeYears(
    pick(
      resumo.cao_idade_anos,
      inputs.idade_cao_anos,
      inputs.cao_idade_anos
    ),
    pick(
      resumo.cao_idade_texto,
      inputs.idade_cao_texto,
      inputs.cao_idade_texto,
      inputs.mensagem_ultima_lead,
      inputs.last_user_message,
      message.content
    )
  );

  const allText = norm([
    safeString(message?.content?.history_for_crm),
    safeString(message?.historico),
    safeString(message?.history_for_crm),
    safeString(message?.content),
    safeString(inputs?.mensagem_ultima_lead),
    safeString(inputs?.mensagem_ultima_bruna),
    safeString(inputs?.last_user_message),
    safeString(inputs?.last_ai_message),
    safeString(inputs?.history_for_crm),
    safeString(resumo?.cao_nome),
    safeString(resumo?.cao_raca),
    safeString(resumo?.cao_sexo),
    safeString(resumo?.cao_castrado),
    safeString(resumo?.cao_no_cio),
    safeString(resumo?.observacoes)
  ].join(' '));

  const latestLeadText = latestLeadTextFrom(j, inputs);
  const previousBrunaText = previousBrunaTextFrom(inputs);

  const sex = inferSexConfidence(
    allText,
    pick(resumo.cao_sexo, inputs.cao_sexo)
  );

  const dogCount = inferDogCount(allText, resumo);

  inputs.sexo_inferido = sex.sexo || '';
  inputs.sexo_inferido_confianca = sex.confidence;
  inputs.quantidade_caes_inferida = dogCount.count || '';
  inputs.quantidade_caes_confianca = dogCount.confidence;

  if (sex.sexo === 'femea' && sex.confidence >= 0.75) {
    inputs.resumo_lead.cao_sexo = pick(resumo.cao_sexo, 'femea');

    if (
      inputs.ultima_intencao === 'MACHO_NAO_CASTRADO' ||
      /machos a partir de 8 meses|macho nao castrado|macho não castrado/.test(norm(inputs.mensagens_resposta.join(' ')))
    ) {
      inputs.status_lead = 'QUALIFICANDO';
      inputs.ultima_intencao = 'INFORMOU_DADOS_CAO';
      inputs.evento_sistema = '';
      inputs.deve_repassar_humano = false;
      inputs.motivo_repasse = '';
      inputs.deve_solicitar_pagamento = false;
      inputs.deve_consultar_agenda = false;
      inputs.deve_criar_pre_reserva = false;
      inputs.deve_encerrar_conversa = false;
      inputs.regra_nao_perfil_objetivo_acionada = false;
      inputs.regra_nao_perfil_motivo = '';

      const hasCio = /\bcio\b|\bprimeiro cio\b/.test(allText);

      const messages = hasCio
        ? [
            'Entendi. A mocinha pode seguir para avaliação, sim.',
            'Só é importante combinar que, se ela estiver no cio, ela não poderá frequentar a AuAu ou AuAuzin nesse período.',
            'Podemos pensar em uma data em que ela já esteja fora do cio.'
          ]
        : [
            'Entendi. Como estamos falando de uma fêmea, essa regra de macho não castrado não se aplica.',
            'Podemos seguir avaliando os próximos passos para ela com calma.'
          ];

      setMessages(j, messages);

      inputs.proxima_acao = 'corrigir falso positivo de macho nao castrado e continuar atendimento';

      inputs.resumo_lead.observacoes = appendObs(
        inputs.resumo_lead.observacoes,
        hasCio
          ? 'Fêmea no cio: atendimento pode seguir, mas frequência/adaptação/hotel devem ocorrer fora do período de cio.'
          : 'Falso positivo de macho não castrado corrigido pelo enforcer.'
      );

      return { json: j };
    }
  }

  if (/\bcio\b|\bprimeiro cio\b/.test(allText)) {
    if (inputs.status_lead === 'ENCERRADO_NAO_PERFIL' && inputs.ultima_intencao !== 'RACA_POTENCIAL_DANO') {
      inputs.status_lead = 'QUALIFICANDO';
      inputs.ultima_intencao = 'INFORMOU_DADOS_CAO';
      inputs.evento_sistema = '';
      inputs.deve_repassar_humano = false;
      inputs.motivo_repasse = '';
      inputs.deve_solicitar_pagamento = false;
      inputs.deve_consultar_agenda = false;
      inputs.deve_criar_pre_reserva = false;
      inputs.deve_encerrar_conversa = false;
      inputs.regra_nao_perfil_objetivo_acionada = false;
      inputs.regra_nao_perfil_motivo = '';

      setMessages(j, [
        'Entendi. A mocinha pode seguir para avaliação, sim.',
        'Só é importante combinar que, se ela estiver no cio, ela não poderá frequentar a AuAu ou AuAuzin nesse período.',
        'Podemos pensar em uma data em que ela já esteja fora do cio.'
      ]);

      inputs.proxima_acao = 'continuar atendimento considerando que femea no cio nao e nao perfil definitivo';
      inputs.resumo_lead.cao_no_cio = 'sim';
      inputs.resumo_lead.observacoes = appendObs(
        inputs.resumo_lead.observacoes,
        'Fêmea no cio: atendimento pode seguir, mas frequência/adaptação/hotel devem ocorrer fora do período de cio.'
      );

      return { json: j };
    }

    inputs.resumo_lead.cao_no_cio = pick(inputs.resumo_lead.cao_no_cio, 'sim');
  }

  if (
    dogCount.count === 'single' &&
    inputs.motivo_repasse === 'caso_ambiguo_multiplos_caes'
  ) {
    inputs.status_lead = 'QUALIFICANDO';
    inputs.ultima_intencao = 'INFORMOU_DADOS_CAO';
    inputs.evento_sistema = '';
    inputs.deve_repassar_humano = false;
    inputs.motivo_repasse = '';
    inputs.deve_encerrar_conversa = false;

    setMessages(j, [
      'Entendi, obrigada por explicar.',
      'Só para eu confirmar certinho: é uma cachorrinha só, certo?'
    ]);

    inputs.proxima_acao = 'confirmar quantidade de caes antes de repassar';
    inputs.resumo_lead.observacoes = appendObs(
      inputs.resumo_lead.observacoes,
      'Enforcer bloqueou repasse por múltiplos cães porque o contexto indica um único cão.'
    );

    return { json: j };
  }

  const hasMixedMultiDogData =
    dogCount.count === 'multiple' &&
    (
      /castrada.*\b(e|,)\b.*nao castrada|nao castrada.*\b(e|,)\b.*castrada/.test(allText) ||
      /castrado.*\b(e|,)\b.*nao castrado|nao castrado.*\b(e|,)\b.*castrado/.test(allText) ||
      /uma\b.*\boutra\b/.test(allText) ||
      /um\b.*\boutro\b/.test(allText)
    );

  if (
    hasMixedMultiDogData &&
    inputs.ultima_intencao === 'MACHO_NAO_CASTRADO' &&
    sex.sexo !== 'macho'
  ) {
    inputs.status_lead = 'TRANSFERIDO_FLAVIA';
    inputs.ultima_intencao = 'PEDIU_HUMANO';
    inputs.evento_sistema = 'REPASSE_FLAVIA';
    inputs.deve_repassar_humano = true;
    inputs.motivo_repasse = 'caso_ambiguo_multiplos_caes';
    inputs.deve_enviar_guia = false;
    inputs.deve_solicitar_pagamento = false;
    inputs.deve_consultar_agenda = false;
    inputs.deve_criar_pre_reserva = false;
    inputs.deve_encerrar_conversa = false;
    inputs.regra_nao_perfil_objetivo_acionada = false;
    inputs.regra_nao_perfil_motivo = '';

    setMessages(j, [
      'Entendi. Como são mais de um cãozinho e o caso tem detalhes específicos, vou encaminhar para a Flávia seguir com você certinho.'
    ]);

    inputs.proxima_acao = 'repassar para humano por caso ambiguo com multiplos caes';
    inputs.resumo_lead.observacoes = appendObs(
      inputs.resumo_lead.observacoes,
      'Caso com múltiplos cães e dados mistos. Repassar para humano.'
    );

    return { json: j };
  }

  const deveConfirmarRaca = isTrueLike(regrasRaca.deve_confirmar_raca);
  const potencialDano = isTrueLike(regrasRaca.potencial_dano);

  if (potencialDano && deveConfirmarRaca) {
    inputs.status_lead = 'QUALIFICANDO';
    inputs.ultima_intencao = 'INFORMOU_DADOS_CAO';
    inputs.evento_sistema = '';
    inputs.deve_repassar_humano = false;
    inputs.motivo_repasse = '';
    inputs.deve_solicitar_pagamento = false;
    inputs.deve_consultar_agenda = false;
    inputs.deve_criar_pre_reserva = false;
    inputs.deve_encerrar_conversa = false;
    inputs.regra_nao_perfil_objetivo_acionada = false;
    inputs.regra_nao_perfil_motivo = '';

    const racaPossivel = pick(regrasRaca.raca_canonica, regrasRaca.raca_detectada, resumo.cao_raca, 'essa raça');

    setMessages(j, [
      `Só para eu confirmar certinho: a raça dele é ${racaPossivel}?`
    ]);

    inputs.proxima_acao = 'confirmar raca antes de aplicar regra de potencial de dano';
    inputs.resumo_lead.observacoes = appendObs(
      inputs.resumo_lead.observacoes,
      'Raça possivelmente enquadrada como potencial de dano, mas precisa confirmação antes de encerrar.'
    );

    return { json: j };
  }

  if (potencialDano) {
    const messages = buildRacaPotencialDanoMessages(tutorNome, caoNome);

    inputs.regra_nao_perfil_objetivo_acionada = true;
    inputs.regra_nao_perfil_motivo = 'RACA_POTENCIAL_DANO';

    inputs.status_lead = 'ENCERRADO_NAO_PERFIL';
    inputs.ultima_intencao = 'RACA_POTENCIAL_DANO';
    inputs.evento_sistema = 'CONVERSA_ENCERRADA';

    inputs.deve_repassar_humano = false;
    inputs.motivo_repasse = '';
    inputs.deve_enviar_guia = false;
    inputs.deve_solicitar_pagamento = false;
    inputs.deve_consultar_agenda = false;
    inputs.deve_criar_pre_reserva = false;
    inputs.deve_encerrar_conversa = true;

    setMessages(j, messages);

    inputs.proxima_acao = 'encerrar atendimento por nao perfil objetivo devido a raca com grande potencial de dano';

    inputs.resumo_lead = {
      ...inputs.resumo_lead,
      tutor_nome: String(tutorNome || resumo.tutor_nome || ''),
      tutor_telefone: String(tutorTelefone || resumo.tutor_telefone || ''),
      cao_nome: String(caoNome || resumo.cao_nome || ''),
      comprovante_recebido: false,
      data_hora_pre_reserva: null,
      responsavel_humano: String(resumo.responsavel_humano || 'Flavia'),
      observacoes: appendObs(resumo.observacoes, 'Encerrado por RACA_POTENCIAL_DANO.')
    };

    inputs.resumo_interno_repasse = {
      ...fillResumoInternoRepasse(resumoInternoRepasse, inputs.resumo_lead, tutorNome, tutorTelefone, caoNome, idadeAnos, inputs),
      repassar_para: '',
      motivo: '',
      comprovante_recebido: false,
      tipo_comprovante: '',
      observacoes: 'Nao perfil objetivo: RACA_POTENCIAL_DANO.'
    };

    return { json: j };
  }

  const sexoMachoAltaConfianca =
    sex.sexo === 'macho' &&
    sex.confidence >= 0.75 &&
    sex.femaleSignals === 0;

  const castrado = pick(
    resumo.cao_castrado,
    inputs.cao_castrado
  );

  const machoNaoCastradoDetectado =
    sexoMachoAltaConfianca &&
    idadeAnos !== null &&
    idadeAnos >= 0.6667 &&
    isFalseLike(castrado);

  if (machoNaoCastradoDetectado) {
    const recusouCastracao = leadRefusedFutureCastration(latestLeadText, previousBrunaText, allText);
    const vaiCastrar = leadWillCastrate(latestLeadText, previousBrunaText, allText);

    inputs.regra_nao_perfil_objetivo_acionada = recusouCastracao;
    inputs.regra_nao_perfil_motivo = 'MACHO_NAO_CASTRADO';

    inputs.ultima_intencao = 'MACHO_NAO_CASTRADO';
    inputs.deve_repassar_humano = false;
    inputs.motivo_repasse = '';
    inputs.deve_enviar_guia = false;
    inputs.deve_solicitar_pagamento = false;
    inputs.deve_consultar_agenda = false;
    inputs.deve_criar_pre_reserva = false;

    if (recusouCastracao) {
      inputs.status_lead = 'ENCERRADO_NAO_PERFIL';
      inputs.evento_sistema = 'CONVERSA_ENCERRADA';
      inputs.deve_encerrar_conversa = true;

      setMessages(j, buildMachoNaoCastradoEncerramentoMessages(tutorNome));

      inputs.proxima_acao = 'encerrar por macho nao castrado sem previsao de castracao';

      inputs.resumo_lead = {
        ...inputs.resumo_lead,
        tutor_nome: String(tutorNome || resumo.tutor_nome || ''),
        tutor_telefone: String(tutorTelefone || resumo.tutor_telefone || ''),
        cao_nome: String(caoNome || resumo.cao_nome || ''),
        cao_sexo: 'macho',
        cao_castrado: 'nao',
        comprovante_recebido: false,
        data_hora_pre_reserva: null,
        responsavel_humano: String(resumo.responsavel_humano || 'Flavia'),
        observacoes: appendObs(resumo.observacoes, 'Encerrado por MACHO_NAO_CASTRADO sem previsão de castração.')
      };

      inputs.resumo_interno_repasse = {
        ...fillResumoInternoRepasse(resumoInternoRepasse, inputs.resumo_lead, tutorNome, tutorTelefone, caoNome, idadeAnos, inputs),
        repassar_para: '',
        motivo: '',
        comprovante_recebido: false,
        tipo_comprovante: '',
        observacoes: 'Nao perfil objetivo: MACHO_NAO_CASTRADO sem previsao de castracao.'
      };

      return { json: j };
    }

    if (vaiCastrar) {
      inputs.status_lead = 'PRE_REPROVADO';
      inputs.evento_sistema = '';
      inputs.deve_encerrar_conversa = false;

      setMessages(j, buildMachoVaiCastrarMessages(tutorNome));

      inputs.proxima_acao = 'aguardar castracao futura antes de seguir para avaliacao';

      inputs.resumo_lead = {
        ...inputs.resumo_lead,
        tutor_nome: String(tutorNome || resumo.tutor_nome || ''),
        tutor_telefone: String(tutorTelefone || resumo.tutor_telefone || ''),
        cao_nome: String(caoNome || resumo.cao_nome || ''),
        cao_sexo: 'macho',
        cao_castrado: 'nao',
        comprovante_recebido: false,
        data_hora_pre_reserva: null,
        observacoes: appendObs(resumo.observacoes, 'Macho não castrado. Tutor sinalizou intenção de castrar futuramente.')
      };

      return { json: j };
    }

    inputs.status_lead = 'PRE_REPROVADO';
    inputs.evento_sistema = '';
    inputs.deve_encerrar_conversa = false;

    setMessages(j, buildMachoNaoCastradoPerguntaMessages(tutorNome));

    inputs.proxima_acao = 'aguardar tutor informar se pretende castrar em breve';

    inputs.resumo_lead = {
      ...inputs.resumo_lead,
      tutor_nome: String(tutorNome || resumo.tutor_nome || ''),
      tutor_telefone: String(tutorTelefone || resumo.tutor_telefone || ''),
      cao_nome: String(caoNome || resumo.cao_nome || ''),
      cao_sexo: 'macho',
      cao_castrado: 'nao',
      comprovante_recebido: false,
      data_hora_pre_reserva: null,
      observacoes: appendObs(resumo.observacoes, 'Macho não castrado com 8 meses ou mais. Aguardando tutor dizer se pretende castrar em breve.')
    };

    return { json: j };
  }

  if (
