  if (index === 0) return false;
  return getMinutesDiff(first.starts_at, slot.starts_at) >= MIN_DIFF_MINUTES;
});

// 2. Se não achar, tenta slot no próximo turno
if (!second) {
  second = slots.find((slot, index) => {
    if (index === 0) return false;
    return slot.local_shift !== first.local_shift;
  });
}

// 3. Se ainda não achar, pega o próximo slot diferente do primeiro
