const item = $input.first().json;

function sanitizeString(value) {
  return String(value)
    .replace(/\[object Object\]/gi, '')
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, ' ')
    .replace(/\uFFFD/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function deepSanitize(value, keyPath = '') {
  const protectedKeys = [
    'data_url',
    'source_id',
    'pubsub_token',
    'hmac_verified'
  ];

  const currentKey = keyPath.split('.').pop() || '';

  if (protectedKeys.includes(currentKey)) {
    return value;
  }

  if (typeof value === 'string') {
    return sanitizeString(value);
  }

  if (Array.isArray(value)) {
    return value.map((item, index) => deepSanitize(item, `${keyPath}[${index}]`));
  }

  if (value && typeof value === 'object') {
    const output = {};
    for (const [key, val] of Object.entries(value)) {
      output[key] = deepSanitize(val, keyPath ? `${keyPath}.${key}` : key);
    }
    return output;
  }

  return value;
}

const sanitized = deepSanitize(item);

return [{ json: sanitized }];

const item = $input.first().json || {};

// ==================================================
// HELPERS
// ==================================================

function pick(...values) {
  for (const v of values) {
    if (v !== undefined && v !== null && String(v).trim() !== '') return v;
  }
  return '';
}

function safeString(value) {
  if (value === undefined || value === null) return '';
  if (typeof value === 'object') {
    try {
      return JSON.stringify(value);
    } catch (error) {
      return '';
    }
  }
  return String(value);
}

function normalizeSpaces(value, preserveNewLines = true) {
  let text = safeString(value)
    .replace(/\[object Object\]/gi, '')
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, ' ')
    .replace(/\uFFFD/g, ' ')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n')
    .trim();

  if (preserveNewLines) {
    return text
      .split('\n')
      .map(line => line.replace(/[ \t]+/g, ' ').trim())
      .filter(Boolean)
      .join('\n')
      .trim();
  }

  return text.replace(/\s+/g, ' ').trim();
}

function toNumberOrNull(value) {
  if (value === undefined || value === null || String(value).trim() === '') return null;

  const n = Number(value);
  return Number.isFinite(n) ? n : null;
}

function asArray(value) {
  if (Array.isArray(value)) return value;

  const candidates = [
    value?.chatwoot?.chatwoot_messages,
    value?.chatwoot_messages,
    value?.messages,
    value?.payload,
    value?.data?.payload,
    value?.data?.messages,
    value?.history_messages,
    value?.historico_mensagens,
    value?.chatwoot_history,
    value?.chatwoot_history_raw,
    value?.history_raw,
    value?.message?.messages,
    value?.message?.payload,
    value?.chatwoot?.messages,
    value?.chatwoot?.payload,
    value?.busca_mensagens?.payload,
    value?.busca_mensagens?.messages
  ];

  for (const candidate of candidates) {
    if (Array.isArray(candidate)) return candidate;
  }

  return [];
}

function getMessageId(msg) {
  return toNumberOrNull(
    msg?.id ??
    msg?.message_id ??
    msg?.chatwoot_message_id
  );
}

function getMessageText(msg) {
  return normalizeSpaces(
    pick(
      msg?.content,
      msg?.text,
      msg?.body,
      msg?.message,
      ''
    ),
    true
  );
}

function getCreatedAt(msg) {
  return pick(
    msg?.created_at,
    msg?.createdAt,
    msg?.timestamp,
    msg?.createdAtIso,
    ''
  );
}

function getSourceId(msg) {
  return pick(
    msg?.source_id,
    msg?.sourceId,
    msg?.external_source_id,
    ''
  );
}

function getAttachments(msg) {
  if (Array.isArray(msg?.attachments)) return msg.attachments;
  if (Array.isArray(msg?.files)) return msg.files;
  if (Array.isArray(msg?.message?.attachments)) return msg.message.attachments;
  return [];
}

function getAttachmentUrl(attachment) {
  return pick(
    attachment?.data_url,
    attachment?.download_url,
    attachment?.file_url,
    attachment?.url,
    attachment?.thumb_url,
    ''
  );
}

function isPrivateMessage(msg) {
  return msg?.private === true || msg?.is_private === true;
}

function isIncomingLeadMessage(msg) {
  if (!msg || typeof msg !== 'object') return false;
  if (isPrivateMessage(msg)) return false;

  const typeRaw = msg?.message_type ?? msg?.type ?? msg?.direction ?? '';
  const type = String(typeRaw).toLowerCase();

  const senderType = String(
    pick(
      msg?.sender_type,
      msg?.sender?.type,
      msg?.sender?.role,
      msg?.sender?.name === 'contact' ? 'contact' : '',
      ''
    )
  ).toLowerCase();

  // Chatwoot:
  // 0 = incoming
  // 1 = outgoing
  if (typeRaw === 0) return true;
  if (typeRaw === 1) return false;

  if (type === 'incoming') return true;
  if (type === 'outgoing') return false;
  if (type === 'activity') return false;

  if (senderType === 'contact') return true;
  if (senderType === 'user' || senderType === 'agent') return false;

  return false;
}

function dedupeEditedMessages(messages) {
  const byKey = new Map();

  for (const msg of messages) {
    const sourceId = String(msg?.source_id || msg?.__source_id || '').trim();
    const replyTo = String(msg?.content_attributes?.in_reply_to || '').trim();

    // Prioridade:
    // source_id identifica a mensagem original do WhatsApp.
    // in_reply_to ajuda nos casos de mensagem editada/transcrição.
    // id é fallback.
    const key = sourceId || replyTo || String(msg?.id || msg?.__id || '');

    const current = byKey.get(key);

    if (!current) {
      byKey.set(key, msg);
      continue;
    }

    const currentId = Number(current?.id || current?.__id || 0);
    const msgId = Number(msg?.id || msg?.__id || 0);

    // Mantém a versão mais nova, útil para "Mensagem editada:"
    if (msgId >= currentId) {
      byKey.set(key, msg);
    }
  }

  return Array.from(byKey.values());
}

function detectMessageModality(hasText, attachments) {
  if (!attachments.length) return 'text_only';

  const first = attachments[0] || {};
  const fileType = String(
    pick(
      first.file_type,
      first.type,
      first.content_type,
      first.mime_type,
      first.fileType,
      ''
    )
  ).toLowerCase();

  let mediaType = 'attachment';

  if (fileType.includes('image')) mediaType = 'image';
  else if (fileType.includes('pdf')) mediaType = 'document';
  else if (fileType.includes('document')) mediaType = 'document';
  else if (fileType.includes('application')) mediaType = 'document';
  else if (fileType.includes('audio')) mediaType = 'audio';
  else if (fileType.includes('video')) mediaType = 'video';
  else if (fileType.includes('file')) mediaType = 'document';

  return hasText ? `${mediaType}_with_text` : `${mediaType}_only`;
}

function buildFallbackCurrentMessage(current) {
  const currentMessageId = toNumberOrNull(
    pick(
      current?.chatwoot?.message_id,
      current?.message?.message_id,
      current?.message_id,
      0
    )
  );

  const content = normalizeSpaces(
    pick(
