  return '';
}

function norm(v) {
  return String(v || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .trim();
}

function pad2(n) {
  return String(n).padStart(2, '0');
}

function toISODate(year, month, day) {
  return `${year}-${pad2(month)}-${pad2(day)}`;
}

function parseDateBR(day, month, fallbackYear) {
  const d = Number(day);
  const m = Number(month);
  const y = Number(fallbackYear);

  if (!d || !m || !y) return null;
  if (m < 1 || m > 12) return null;
  if (d < 1 || d > 31) return null;

  const date = new Date(Date.UTC(y, m - 1, d));

  if (
    date.getUTCFullYear() !== y ||
    date.getUTCMonth() !== m - 1 ||
    date.getUTCDate() !== d
  ) {
    return null;
  }

  return toISODate(y, m, d);
}

function daysBetweenISO(startISO, endISO) {
  if (!startISO || !endISO) return null;

  const start = new Date(`${startISO}T00:00:00Z`);
  const end = new Date(`${endISO}T00:00:00Z`);

  const diff = Math.round((end - start) / (1000 * 60 * 60 * 24));

  return diff > 0 ? diff : null;
}

function extractPeriod(text) {
  const t = norm(text);

  const now = new Date();
  const currentYear = now.getFullYear();

  // Exemplos:
  // 13 a 27/06
  // 13/06 a 27/06
  // de 13 a 27/06
  // de 13/06 até 27/06
  const patterns = [
    /(?:de\s*)?(\d{1,2})\/(\d{1,2})\s*(?:a|ate|até|-)\s*(\d{1,2})\/(\d{1,2})/,
    /(?:de\s*)?(\d{1,2})\s*(?:a|ate|até|-)\s*(\d{1,2})\/(\d{1,2})/
  ];

  for (const p of patterns) {
    const m = t.match(p);

    if (!m) continue;

    if (m.length === 5) {
      const startDay = m[1];
      const startMonth = m[2];
      const endDay = m[3];
      const endMonth = m[4];

      const startISO = parseDateBR(startDay, startMonth, currentYear);
      const endISO = parseDateBR(endDay, endMonth, currentYear);

      return { startISO, endISO };
    }

    if (m.length === 4) {
      const startDay = m[1];
      const endDay = m[2];
      const month = m[3];

      const startISO = parseDateBR(startDay, month, currentYear);
      const endISO = parseDateBR(endDay, month, currentYear);

      return { startISO, endISO };
    }
  }

  return { startISO: '', endISO: '' };
}

function calcHotelEstimate(diarias) {
  if (!diarias) return null;

  const baixa = 165;
  const alta = 180;

  const totalBaixaAvulso = diarias * baixa;
  const totalAltaAvulso = diarias * alta;

  const pacotes = [
    { nome: 'pacote_10_diarias', diarias: 10, valor: 1430 },
    { nome: 'pacote_20_diarias', diarias: 20, valor: 2530 },
    { nome: 'pacote_30_diarias', diarias: 30, valor: 3400 }
  ];

  const pacoteMaisProximo = pacotes
    .filter(p => p.diarias >= diarias)
    .sort((a, b) => a.diarias - b.diarias)[0] || null;

  return {
    diarias_estimadas: diarias,
    valor_baixa_temporada_avulso: totalBaixaAvulso,
    valor_alta_temporada_avulso: totalAltaAvulso,
    pacote_sugerido: pacoteMaisProximo,
    observacao: 'Estimativa automática. Confirmar check-in, check-out, temporada e disponibilidade com humano antes de fechar.'
  };
}

