const original = $('Histórico Atualizado').first().json;
const currentMessageId = Number(original.current_message_id);

const root = $input.first().json;
const messages = Array.isArray(root.payload) ? root.payload : [];

// ordenar por id crescente
messages.sort((a, b) => Number(a.id) - Number(b.id));

// vamos pegar a sequência final de mensagens do lead
const grouped = [];

// encontrar o índice da mensagem atual
const currentIndex = messages.findIndex(m => Number(m.id) === currentMessageId);

if (currentIndex === -1) {
  return [
    {
      json: {
        merged_lead_message: original.message || '',
        grouped_message_ids: [currentMessageId]
      }
    }
  ];
}

// andar para trás a partir da mensagem atual
for (let i = currentIndex; i >= 0; i--) {
  const msg = messages[i];
  const type = Number(msg.message_type);

  if (type === 0) {
    grouped.unshift(msg); // incoming do lead
  } else {
    // se encontrou outgoing ou system antes do bloco atual, para
    if (grouped.length > 0) break;
  }
}

const mergedText = grouped
  .map(m => (m.content || '').trim())
  .filter(Boolean)
  .join('\n');

return [
  {
    json: {
      message: mergedText || original.message || '',
//      grouped_message_ids: grouped.map(m => m.id)
    }
  }
];

