function inferSexConfidence(allText, sexoCampo) {
  const sexoNorm = norm(sexoCampo);

  const explicitFemale =
    /\bfemea\b/.test(allText) ||
    /\bfemeas\b/.test(allText);

  const explicitMale =
    /\bmacho\b/.test(allText) ||
    /\bmachos\b/.test(allText);

  const femaleSignals = [
    explicitFemale,
    /\bela\b/.test(allText),
    /\bdela\b/.test(allText),
    /\bmocinha\b/.test(allText),
    /\bmenina\b/.test(allText),
    /\bcadelinha\b/.test(allText),
    /\bcadela\b/.test(allText),
    /\bcastrada\b/.test(allText),
    /\bnao castrada\b/.test(allText),
    /\bcio\b/.test(allText),
    /\bprimeiro cio\b/.test(allText),
    sexoNorm.includes('femea')
  ].filter(Boolean).length;

  const maleSignals = [
    explicitMale,
    /\bele\b/.test(allText),
    /\bdele\b/.test(allText),
    /\bmenino\b/.test(allText),
    /\bmocinho\b/.test(allText),
    /\brapazinho\b/.test(allText),
    /\bcastrado\b/.test(allText),
    /\bnao castrado\b/.test(allText),
    sexoNorm.includes('macho')
  ].filter(Boolean).length;

  const hasFemaleStrong = explicitFemale || /\bela\b|\bdela\b|\bcio\b|\bprimeiro cio\b|\bcastrada\b|\bnao castrada\b/.test(allText);
  const hasMaleStrong = explicitMale || /\bmacho\b|\bele\b|\bdele\b|\bnao castrado\b|\bcastrado\b/.test(allText);

  if (hasFemaleStrong && !explicitMale) {
    return { sexo: 'femea', confidence: 0.95, femaleSignals, maleSignals, conflict: maleSignals > 0 };
  }

  if (hasMaleStrong && !explicitFemale && femaleSignals === 0) {
    return { sexo: 'macho', confidence: 0.9, femaleSignals, maleSignals, conflict: false };
  }

  if (explicitFemale && explicitMale) {
    return { sexo: '', confidence: 0.25, femaleSignals, maleSignals, conflict: true };
  }

  if (femaleSignals > maleSignals && femaleSignals >= 2) {
    return { sexo: 'femea', confidence: 0.75, femaleSignals, maleSignals, conflict: maleSignals > 0 };
  }

  if (maleSignals > femaleSignals && maleSignals >= 2) {
    return { sexo: 'macho', confidence: 0.75, femaleSignals, maleSignals, conflict: femaleSignals > 0 };
  }

  return { sexo: '', confidence: 0.3, femaleSignals, maleSignals, conflict: femaleSignals > 0 && maleSignals > 0 };
}

function inferDogCount(allText, resumo) {
  const nome = norm(resumo?.cao_nome || '');
  const castracao = norm(resumo?.cao_castrado || '');

  const hasTwoNamesInField =
    /\b[a-z]{2,}\s+e\s+[a-z]{2,}\b/.test(nome) &&
    !/maia\s+e\s+.*maio/.test(nome);

  const strongMultiSignals = [
    /\bduas\b/.test(allText),
    /\bdois\b/.test(allText),
    /\bas duas\b/.test(allText),
    /\bos dois\b/.test(allText),
    /\belas sao\b/.test(allText),
    /\beles sao\b/.test(allText),
    /\buma\b.*\boutra\b/.test(allText),
    /\bum\b.*\boutro\b/.test(allText),
    hasTwoNamesInField,
    /suzy.*maya|maya.*suzy/.test(allText),
    /castrada.*\b(e|,)\b.*nao castrada|nao castrada.*\b(e|,)\b.*castrada/.test(allText),
    /castrado.*\b(e|,)\b.*nao castrado|nao castrado.*\b(e|,)\b.*castrado/.test(allText)
  ].filter(Boolean).length;

  const strongSingleSignals = [
    /\buma so\b/.test(allText),
    /\bum so\b/.test(allText),
    /\bso uma\b/.test(allText),
    /\bso um\b/.test(allText),
    /\bela\b/.test(allText),
    /\bele\b/.test(allText),
    /\bminha filha\b/.test(allText),
    /\bmeu filho\b/.test(allText),
    /ela tem .* vai fazer/.test(allText),
    /ele tem .* vai fazer/.test(allText),
    /maia.*raca.*labrador.*idade.*seis.*vai fazer sete.*maio/.test(allText),
    /idade.*seis.*vai fazer sete/.test(allText)
  ].filter(Boolean).length;

  if (strongMultiSignals >= 2) {
    return { count: 'multiple', confidence: 0.9, strongMultiSignals, strongSingleSignals };
  }

  if (strongSingleSignals >= 2 && strongMultiSignals < 2) {
    return { count: 'single', confidence: 0.85, strongMultiSignals, strongSingleSignals };
  }

  if (strongMultiSignals === 1 && strongSingleSignals === 0) {
    return { count: 'possible_multiple', confidence: 0.55, strongMultiSignals, strongSingleSignals };
  }

  return { count: '', confidence: 0.3, strongMultiSignals, strongSingleSignals };
}

