  return explicitRefusal || shortNoAfterQuestion;
}

function leadWillCastrate(latestLeadText, previousBrunaText, allText) {
  const previousAsked =
    /pensa em castra|pretende castra|vai castra|castra-lo em breve|castra lo em breve/.test(previousBrunaText) ||
    /pensa em castra|pretende castra|vai castra|castra-lo em breve|castra lo em breve/.test(allText);

  const explicitYes =
    /vou castra|pretendo castra|penso em castra|quero castra|em breve|assim que/.test(allText);

  const shortYesAfterQuestion =
    previousAsked &&
    /^(sim|s|positivo|pretendo|vou|penso)(\b|\.|!|\?|$)/.test(latestLeadText);

  return explicitYes || shortYesAfterQuestion;
}

function fillResumoInternoRepasse(base, resumo, tutorNome, tutorTelefone, caoNome, idadeAnos, inputs) {
  return {
