    cao_porte: String(pick(base.cao_porte, resumo.cao_porte, inputs.cao_porte, '') || ''),
    cao_sexo: String(pick(base.cao_sexo, resumo.cao_sexo, inputs.cao_sexo, '') || ''),
    cao_castrado: String(pick(base.cao_castrado, resumo.cao_castrado, inputs.cao_castrado, '') || ''),
    cao_vacinas_ok: String(pick(base.cao_vacinas_ok, resumo.cao_vacinas_ok, inputs.cao_vacinas_ok, '') || ''),
    cao_antipulgas_ok: String(pick(base.cao_antipulgas_ok, resumo.cao_antipulgas_ok, inputs.cao_antipulgas_ok, '') || ''),
    cao_sociavel: String(pick(base.cao_sociavel, resumo.cao_sociavel, inputs.cao_sociavel, '') || ''),
    cao_reativo: String(pick(base.cao_reativo, resumo.cao_reativo, inputs.cao_reativo, '') || ''),
    unidade_preferida: String(pick(base.unidade_preferida, resumo.unidade_preferida, inputs.unidade_preferida, '') || ''),
    servico_interesse: String(pick(base.servico_interesse, resumo.servico_interesse, inputs.servico_interesse, '') || ''),
    data_hora_avaliacao: pick(base.data_hora_avaliacao, null),
