  inputs.status_lead = inputs.status_lead ?? '';
  inputs.ultima_intencao = inputs.ultima_intencao ?? '';
  inputs.evento_sistema = inputs.evento_sistema ?? '';
  inputs.proxima_acao = inputs.proxima_acao ?? '';

  inputs.deve_repassar_humano = Boolean(inputs.deve_repassar_humano);
  inputs.motivo_repasse = inputs.motivo_repasse ?? '';
  inputs.deve_enviar_guia = Boolean(inputs.deve_enviar_guia);
  inputs.deve_solicitar_pagamento = Boolean(inputs.deve_solicitar_pagamento);
  inputs.deve_consultar_agenda = Boolean(inputs.deve_consultar_agenda);
  inputs.deve_criar_pre_reserva = Boolean(inputs.deve_criar_pre_reserva);
