      inputs.cao_idade_texto,
      inputs.mensagem_ultima_lead,
      inputs.last_user_message,
      message.content
    )
  );

  const allText = norm([
    safeString(message?.content?.history_for_crm),
    safeString(message?.historico),
    safeString(message?.history_for_crm),
    safeString(message?.content),
    safeString(inputs?.mensagem_ultima_lead),
    safeString(inputs?.mensagem_ultima_bruna),
    safeString(inputs?.last_user_message),
    safeString(inputs?.last_ai_message),
