  }

  if (
    dogCount.count === 'single' &&
    inputs.motivo_repasse === 'caso_ambiguo_multiplos_caes'
  ) {
    inputs.status_lead = 'QUALIFICANDO';
    inputs.ultima_intencao = 'INFORMOU_DADOS_CAO';
